### Dialog
```typescript
// src/components/new-workflow-dialog.tsx
"use client";

import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Select } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";

interface NewWorkflowDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSubmit: (input: WorkflowInput) => void;
}

export function NewWorkflowDialog({ open, onOpenChange, onSubmit }: NewWorkflowDialogProps) {
  const [premise, setPremise] = useState("");
  const [voice, setVoice] = useState("Gianna");
  const [generateImages, setGenerateImages] = useState(true);
  const [stitchVideo, setStitchVideo] = useState(true);
  const [targetWordCount, setTargetWordCount] = useState(5000);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      await onSubmit({
        workflow_type: "content_pipeline",
        input: {
          premise,
          voice_name: voice,
          generate_images: generateImages,
          stitch_video: stitchVideo,
          target_word_count: targetWordCount,
        },
      });
      onOpenChange(false);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>New Content Pipeline</DialogTitle>
        </DialogHeader>
        {/* Form fields */}
      </DialogContent>
    </Dialog>
  );
}
```

